		//OTB -- START
		public function getAgendafield($stage,$form_id)
		{
			$q=$this->createQuery('f')
				->select('f.entry_id,f.application_id,f.date_of_submission,f.user_id,u.fullname,u.registeras,r.name,i.invoice_number,i.total_amount,c.id,c.short_name,c.description,a.id')
				->leftJoin('f.mfInvoice i')
				->leftJoin('f.User u')
				->leftJoin('u.sfGuardUserCategories r')
				->leftJoin('f.ApprovalCondition a')
				->leftJoin('a.Condition c')
				->where('f.approved =? AND f.form_id =?',array($stage,$form_id));
			return $q->fetchArray();
		}
		protected static $columns_agenda=array('application_id' => 'Application id','date_of_submission' => 'Date of submission','fullname' => 'Applicant','invoice_number' => 'Invoice no.','total_amount' => 'Invoice amount','paid' => 'Invoice status','conditions' => 'Conditions','registered_as' => 'User category','membership_address' => 'Applicant address','days' => 'Days taken','membership_no' => 'Applicant Membership no');
		public function getColumnsAgenda()
		{
			return self::$columns_agenda;
