		//OTB ADD
		public function getDaysinCirculation($date_of_submission,$application_id)
		{
			$days=round((time()-strtotime($date_of_submission))/86400);
			error_log('-----DaYs -----'.$days);
			//Check for days it has stayed with client
			$q = Doctrine_Query::create()
			   ->from("ApplicationReference a")
			   ->where("a.application_id = ? AND a.stage_id IN (SELECT e.id FROM SubMenus e WHERE e.stage_type = 5)", $application_id);
			$references = $q->execute();
			$totaldays = 0;
			foreach($references as $reference)
			{
			  if($reference->getEndDate() != "")
			  {
				$correction_days = round((strtotime($reference->getEndDate())-strtotime($reference->getStartDate()))/86400);
			  }
			  else
			  {
				$correction_days = round((time()-strtotime($reference->getStartDate()))/86400);
			  }
			  $totaldays+=$correction_days;
			}
			
			if($totaldays < $days)
			{
				$days=$days-$totaldays;
			}
			return $days;
		}
		public function integerToRoman($integer,$roman_type='small')
		{
		 // Convert the integer into an integer (just to make sure)
		 $integer = intval($integer);
		 $result = '';
		 
		 // Create a lookup array that contains all of the Roman numerals.
		 $lookup_capital = array('M' => 1000,
		 'CM' => 900,
		 'D' => 500,
		 'CD' => 400,
		 'C' => 100,
		 'XC' => 90,
		 'L' => 50,
		 'XL' => 40,
		 'X' => 10,
		 'IX' => 9,
		 'V' => 5,
		 'IV' => 4,
		 'I' => 1);
		 $lookup_small = array('m' => 1000,
		 'cm' => 900,
		 'd' => 500,
		 'cd' => 400,
		 'c' => 100,
		 'xc' => 90,
		 'l' => 50,
		 'xl' => 40,
		 'x' => 10,
		 'ix' => 9,
		 'v' => 5,
		 'iv' => 4,
		 'i' => 1);
		 if($roman_type == 'small'){
			$lookup=$lookup_small;
		 }else{
			$lookup=$lookup_capital;
		 }
		 foreach($lookup as $roman => $value){
		  // Determine the number of matches
		  $matches = intval($integer/$value);
		 
		  // Add the same number of characters to the string
		  $result .= str_repeat($roman,$matches);
		 
		  // Set the integer to be the remainder of the integer and the value
		  $integer = $integer % $value;
		 }
		 
		 // The Roman numeral should be built, return it
		 return $result;
		}
